INSERT INTO mi_practice_modules (
    id,
    code,
    title,
    mi_focus_area,
    difficulty_level,
    estimated_minutes,
    learning_objective,
    scenario_context,
    persona_config,
    dialogue_structure,
    target_competencies,
    maps_rubric,
    is_active
) VALUES (
    '07b9bf4c-239a-4f2a-93f0-6ac6fc3c5145',
    'maps-change-talk-recognition-and-ev-006',
    'Module 6: Recognizing and Evoking Change Talk (DARN-CAT)',
    'Eliciting Change Talk',
    'intermediate',
    20,
    'Learn to recognize different types of change talk, selectively reflect change talk to strengthen it, and use strategic questions to evoke change talk across the DARN-CAT spectrum',
    'A colleague is considering stepping into a team leadership role but feels ambivalent. Practice recognizing and evoking change talk using the DARN-CAT framework (Desire, Ability, Reasons, Need, Commitment, Activation, Taking steps).',
    '{"name": "Marcus", "role": "colleague", "background": "Senior customer advisor being considered for team lead position. Has strong technical skills but uncertain about leadership responsibilities.", "personality_traits": ["thoughtful", "cautious", "competent", "ambivalent"], "tone_spectrum": {"word_complexity": 0.4, "sentence_length": 0.4, "emotional_expressiveness": 0.3, "disclosure_level": 0.3, "response_latency": 0.4, "confidence_level": 0.3}, "starting_tone_position": 0.3, "triggers": ["pressure", "being told what to do", "dismissiveness"], "comfort_topics": ["autonomy", "recognition", "growth", "support"]}'::jsonb,
    '{"start_node_id": "node_1", "nodes": {"node_1": {"id": "node_1", "persona_text": "I''ve been thinking more about the team lead role since we last talked. One of the newer team members came to me yesterday with a complex case - I helped them figure it out and they were so grateful. It felt good to guide them.", "persona_mood": "neutral_uncertain", "themes": ["Motivation", "Change", "Goals"], "choice_points": [{"id": "cp_node_1_0", "option_text": "That''s great! You should definitely apply for the role then.", "preview_hint": "Directive approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This jumps straight to advice without exploring their change talk. You missed the opportunity to reflect their Desire change talk (''it felt good'').", "learning_note": "Always reflect change talk when it appears to strengthen it."}, "next_node_id": "node_2a", "exploration_depth": "surface"}, {"id": "cp_node_1_1", "option_text": "You felt good helping that team member figure things out. There was something satisfying about guiding them through that complex case.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["simple_reflection", "double_sided"], "competency_links": ["B6", "A6"], "feedback": {"immediate": "Excellent! This selectively reflects the Desire change talk (''felt good'') and the positive experience. Reflecting change talk strengthens it.", "learning_note": "Reflections build rapport by showing you understand the colleague''s perspective."}, "next_node_id": "node_2b", "exploration_depth": "surface"}, {"id": "cp_node_1_2", "option_text": "You''re already doing leadership work informally. Might as well make it official.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This pushes toward commitment when they''re only expressing Desire. The pace is too fast - stay with and reflect what they''ve offered.", "learning_note": "Match your response to the level of change talk present."}, "next_node_id": "node_2c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2a": {"id": "node_2a", "persona_text": "I don''t know. It''s just one example. Being a team lead is a lot more than helping with one case.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_2a_0", "option_text": "You''re right, there''s much more to it. But tell me more about that moment when you helped them - what was satisfying about it?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You acknowledge their concern while redirecting back to the Desire change talk they offered.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_3a", "exploration_depth": "surface"}, {"id": "cp_node_2a_1", "option_text": "Well, you can learn the rest. Everyone has to start somewhere.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This dismisses their concern and pushes a solution. You''re missing the opportunity to explore their ambivalence.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2b": {"id": "node_2b", "persona_text": "It really did. I like sharing what I''ve learned over the years. And seeing them get it - that lightbulb moment - that was rewarding. But then I also think about all the other stuff that comes with being a lead.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation", "Barriers"], "choice_points": [{"id": "cp_node_2b_0", "option_text": "You enjoy mentoring and seeing others succeed. The teaching part appeals to you.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good - this reflects the Desire change talk about mentoring. But it ignores the ambivalence they just expressed.", "learning_note": "When there''s ambivalence, reflect both sides rather than just one."}, "next_node_id": "node_3b", "exploration_depth": "surface"}, {"id": "cp_node_2b_1", "option_text": "There''s something real that draws you to leadership - the mentoring, seeing others grow. And at the same time, you''re aware of the other responsibilities and what they would entail.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["double_sided_reflection"], "competency_links": ["B6"], "feedback": {"immediate": "Perfect! This reflects both the Desire change talk AND their ambivalence. This honors the full complexity of their position.", "learning_note": "Double-sided reflections acknowledge ambivalence while still reflecting change talk."}, "next_node_id": "node_3c", "exploration_depth": "surface"}, {"id": "cp_node_2b_2", "option_text": "What concerns you about the other responsibilities?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This question focuses on the sustain talk side. You want to elicit change talk, not sustain talk.", "learning_note": "Focus questions on evoking change talk, not sustaining the status quo."}, "next_node_id": "node_3d", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2c": {"id": "node_2c", "persona_text": "Maybe. But I''m not sure informal helping is the same as formal leadership. There''s performance reviews, schedules, conflict resolution... lots I haven''t done.", "persona_mood": "neutral_uncertain", "themes": ["Barriers", "Change"], "choice_points": [{"id": "cp_node_2c_0", "option_text": "Those are all skills you can learn. What makes you think you couldn''t learn them?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This challenges their concern and pushes them to justify themselves. It doesn''t evoke Ability change talk in a collaborative way.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_end_poor", "exploration_depth": "surface"}, {"id": "cp_node_2c_1", "option_text": "You''re recognizing there are new responsibilities you haven''t taken on before - performance reviews, scheduling, managing conflicts. And you''re wondering whether you have the ability to handle those.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good reflection that captures their concern about Ability. Now you could evoke Ability change talk by asking about related skills.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_3e", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3a": {"id": "node_3a", "persona_text": "It was satisfying to see them solve the problem themselves. I just pointed them in the right direction. That''s what I like - helping people find answers, not giving them answers.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation"], "choice_points": [{"id": "cp_node_3a_0", "option_text": "That''s exactly what good leadership is - guiding people to find their own answers. You have a natural approach to it.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.2, "technique_tags": ["affirmation", "reflection"], "competency_links": ["A6", "B6"], "feedback": {"immediate": "Excellent! This is an affirmation that also reflects their Ability change talk. It builds confidence while connecting to leadership skills.", "learning_note": "Affirmations that reflect strengths are powerful for building self-efficacy."}, "next_node_id": "node_4a", "exploration_depth": "surface"}, {"id": "cp_node_3a_1", "option_text": "So you think you could be a good leader then?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This is a closed question that demands a yes/no answer. Open questions that evoke more change talk are more effective.", "learning_note": "Use open questions to explore rather than closed questions that demand answers."}, "next_node_id": "node_4b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3b": {"id": "node_3b", "persona_text": "Right, I do enjoy that part. It''s rewarding when someone you''ve helped succeeds. I''ve been doing this 8 years - I have a lot to share.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation", "Change"], "choice_points": [{"id": "cp_node_3b_0", "option_text": "Eight years of experience gives you a wealth of knowledge to draw on. What else makes you think you might be ready for this step?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good! This reflects their Ability (experience) and asks an open question to evoke more change talk.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_4c", "exploration_depth": "surface"}, {"id": "cp_node_3b_1", "option_text": "With 8 years of experience, you''re definitely qualified. You should go for it.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This reassurance and advice doesn''t evoke their own change talk. It takes control away from them.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_4d", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3c": {"id": "node_3c", "persona_text": "Exactly. Part of me wants it. I can see myself growing into that role. But I also worry about the time commitment, the responsibility for others'' performance...", "persona_mood": "neutral_uncertain", "themes": ["Change", "Barriers"], "choice_points": [{"id": "cp_node_3c_0", "option_text": "So you can see yourself growing as a leader. What does that growth look like to you?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["open_question"], "competency_links": ["B6"], "feedback": {"immediate": "Perfect! You focus on the Desire/Ability change talk (''can see myself growing'') and use an open question to evoke more.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_4e", "exploration_depth": "surface"}, {"id": "cp_node_3c_1", "option_text": "The time commitment isn''t that bad. Most team leads manage it fine.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This dismisses their concern rather than exploring it. You''re arguing for change instead of evoking their own motivation.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_4f", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3d": {"id": "node_3d", "persona_text": "Performance reviews mainly. I''ve never had to give feedback on someone''s work. What if I mess that up? What if someone complains?", "persona_mood": "neutral_uncertain", "themes": ["Barriers", "Change"], "choice_points": [{"id": "cp_node_3d_0", "option_text": "You''re concerned about managing performance conversations. What skills do you think might help with that?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This question focuses on their concern (sustain talk). It would be better to evoke Ability change talk.", "learning_note": "Focus questions on evoking change talk, not exploring sustain talk."}, "next_node_id": "node_4g", "exploration_depth": "surface"}, {"id": "cp_node_3d_1", "option_text": "Managing difficult conversations is a skill. What experience do you already have that might relate to performance discussions?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Better! This asks about existing Ability while acknowledging their concern. It evokes Ability change talk.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_4h", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3e": {"id": "node_3e", "persona_text": "Yeah, exactly. I''ve done customer service for 8 years, I can handle difficult conversations with customers. Maybe some of those skills transfer?", "persona_mood": "neutral_uncertain", "themes": ["Change", "Goals"], "choice_points": [{"id": "cp_node_3e_0", "option_text": "Eight years of handling difficult customer conversations - that''s a lot of relevant experience. What from those conversations might help with performance discussions?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.2, "technique_tags": ["reflection", "open_question"], "competency_links": ["A6", "B6"], "feedback": {"immediate": "Excellent! This affirms their existing Ability and asks an open question to help them see the transferability of their skills.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_4i", "exploration_depth": "surface"}, {"id": "cp_node_3e_1", "option_text": "Of course they transfer! You''re clearly qualified.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This reassures rather than helping them discover it themselves. Let them make the connection.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_4j", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4a": {"id": "node_4a", "persona_text": "That''s kind of you to say. Maybe I do have some of the skills already. I know the systems inside and out, I know the common issues customers face...", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_4a_0", "option_text": "So you have deep technical knowledge and years of customer experience. Those are foundations that would help you succeed as a team lead.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["complex_reflection"], "competency_links": ["B6"], "feedback": {"immediate": "Perfect! This reflects their Ability change talk and connects it to the leadership role. This builds confidence.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5a", "exploration_depth": "surface"}, {"id": "cp_node_4a_1", "option_text": "What about your concerns? What if you''re not ready?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This shifts to sustain talk concerns when Ability change talk is flowing. Stay with and strengthen the change talk.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4b": {"id": "node_4b", "persona_text": "I... I don''t know. Maybe. I''m just thinking about it.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_4b_0", "option_text": "You''re in the thinking stage, considering what leadership might mean for you. What''s drawing you to consider it?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You accept their pace and ask an open question to evoke Desire change talk.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4c": {"id": "node_4c", "persona_text": "Well, I''ve been a mentor to new hires before. I usually get assigned the trainees because I''m patient and thorough. People seem to trust me.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation", "Change"], "choice_points": [{"id": "cp_node_4c_0", "option_text": "So mentoring trainees - that''s something you''re already doing, and people respond well to your approach. That''s evidence you can lead others.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.2, "technique_tags": ["complex_reflection"], "competency_links": ["A6", "B6"], "feedback": {"immediate": "Excellent! This reflects their existing leadership experience as evidence of Ability. This builds on past success.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5d", "exploration_depth": "surface"}, {"id": "cp_node_4c_1", "option_text": "That''s great! So when do you want to apply?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Moving to action planning too quickly. They''re sharing Ability change talk but haven''t expressed commitment.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5e", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4e": {"id": "node_4e", "persona_text": "I guess I imagine myself having more impact. Instead of just handling my own cases, I could help shape how the whole team approaches things. I could share best practices, help newer advisors develop faster.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation", "Change"], "choice_points": [{"id": "cp_node_4e_0", "option_text": "That''s a clear vision - having broader impact beyond your own cases. You could shape team approach and accelerate others'' development. That matters to you.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.2, "technique_tags": ["complex_reflection"], "competency_links": ["B6"], "feedback": {"immediate": "Perfect! This reflects their Desire change talk about the impact they want to have. Vision is powerful motivation.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5f", "exploration_depth": "surface"}, {"id": "cp_node_4e_1", "option_text": "What''s stopping you from doing that now?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This question challenges them and evokes sustain talk. Change talk was flowing - stay with it.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5g", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4f": {"id": "node_4f", "persona_text": "I guess so. But I value my work-life balance. What if the role consumes me?", "persona_mood": "neutral_uncertain", "themes": ["Barriers", "Change"], "choice_points": [{"id": "cp_node_4f_0", "option_text": "Work-life balance is important to you. You don''t want a role that would take that away.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This reflects the sustain talk. To evoke change talk, you might ask what they want or how they see themselves maintaining balance.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5h", "exploration_depth": "surface"}, {"id": "cp_node_4f_1", "option_text": "So balance matters to you. What would a leadership role need to look like for you to maintain that balance?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Better! This acknowledges their concern while evoking change talk about what they want/need from the role.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5i", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4g": {"id": "node_4g", "persona_text": "I don''t know. Being direct but respectful? Listening? Those are things I do with customers.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_4g_0", "option_text": "Exactly - being direct, respectful, listening. Those are skills you use every day. They apply to performance conversations too.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good - this helps them see their existing skills transfer. But you''re telling rather than asking.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5j", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4h": {"id": "node_4h", "persona_text": "Well, I handle escalated complaints all the time. Those are basically performance conversations - helping someone understand what went wrong and how to fix it. And I stay calm in those.", "persona_mood": "neutral_uncertain", "themes": ["Change", "Goals"], "choice_points": [{"id": "cp_node_4h_0", "option_text": "That''s a great connection - escalated complaints involve similar skills to performance discussions. And you stay calm in difficult conversations. That says something about your abilities.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.2, "technique_tags": ["affirmation", "reflection"], "competency_links": ["A6", "B6"], "feedback": {"immediate": "Excellent! You affirm their insight, connect their existing experience to the new challenge, and highlight their Ability.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5k", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4i": {"id": "node_4i", "persona_text": "I guess listening is huge. In customer service, you have to really hear what the issue is before you can help. And staying calm when someone''s upset - that''s something I''ve learned. Also explaining things clearly and patiently.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_4i_0", "option_text": "So you have several relevant skills - listening, staying calm under pressure, explaining things patiently. These are all things that would help you in performance conversations.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["complex_reflection"], "competency_links": ["B6"], "feedback": {"immediate": "Perfect! This reflects their Ability change talk and confirms how it transfers to leadership responsibilities.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5l", "exploration_depth": "surface"}, {"id": "cp_node_4i_1", "option_text": "Those are good skills. But performance reviews are different from customer conversations.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This undermines the Ability change talk they just expressed. Focus on strengthening, not weakening their confidence.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5m", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4j": {"id": "node_4j", "persona_text": "I suppose. But I also need to think about whether I want the extra responsibility right now. My personal life is busy too.", "persona_mood": "neutral_uncertain", "themes": ["Barriers", "Change"], "choice_points": [{"id": "cp_node_4j_0", "option_text": "There''s a lot to consider - the role, your personal life, timing. What feels most important to think through?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good - this is an open question that lets them decide what to explore. It honors their process.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_5n", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5a": {"id": "nodea", "persona_text": "Those are good points. I hadn''t really thought about it that way - that I already have foundations to build on. Maybe I''m underselling myself.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_5a_0", "option_text": "You''re recognizing that you have more relevant experience than you''d acknowledged. That''s an important realization.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["reflection", "affirmation"], "competency_links": ["A6", "B6"], "feedback": {"immediate": "Excellent! This reflects their insight and affirms their growing self-awareness about their abilities.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5b": {"id": "node_5b", "persona_text": "Those are good points. I hadn''t really thought about it that way - that I already have foundations to build on. Maybe I''m underselling myself.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_5b_0", "option_text": "You''re recognizing that you have more relevant experience than you''d acknowledged. That''s an important realization.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["reflection", "affirmation"], "competency_links": ["A6", "B6"], "feedback": {"immediate": "Excellent! This reflects their insight and affirms their growing self-awareness about their abilities.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5c": {"id": "node_5c", "persona_text": "I think it''s the chance to grow. I''ve been in my role a while and I''m ready for something new. I want to be challenged more.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation", "Change"], "choice_points": [{"id": "cp_node_5c_0", "option_text": "So growth and new challenges - you''re feeling ready to stretch beyond your current role. That''s what''s drawing you toward leadership.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["complex_reflection"], "competency_links": ["B6"], "feedback": {"immediate": "Perfect! This reflects their Desire change talk about growth and challenge.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5d": {"id": "node_5d", "persona_text": "I never really thought of it that way. Being assigned trainees because I''m good at it... that is kind of evidence, isn''t it?", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_5d_0", "option_text": "It is evidence - both that others see leadership qualities in you, and that you''ve successfully helped others develop. Those are real abilities you''ve already demonstrated.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["affirmation", "reflection"], "competency_links": ["A6", "B6"], "feedback": {"immediate": "Excellent! This affirms their insight and strengthens their Ability change talk with evidence.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5e": {"id": "node_5e", "persona_text": "Whoa, slow down. I''m just thinking out loud here. I haven''t decided anything.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5e_0", "option_text": "You''re absolutely right - I got ahead of myself. You''re exploring what this might mean, not deciding yet. Tell me more about what you''re thinking.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You acknowledge jumping ahead and return to exploring their thoughts.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5f": {"id": "node_5f", "persona_text": "Exactly. I want to contribute more. To leave things better than I found them. That''s important to me - to have impact beyond my own cases.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Motivation", "Change"], "choice_points": [{"id": "cp_node_5f_0", "option_text": "Leaving things better - having broader impact - that''s a value that matters to you. Leadership could be a way to express that value.", "preview_hint": "MI-consistent approac